<?php require_once "../api/db.php"; $conn = getAppDB(); $token = $_GET['token'] ?? ''; $message = ""; $type = "danger"; if (!$token) { $message = "Invalid verification link."; } else { $stmt = $conn->prepare(" SELECT id, verify_expires, is_verified FROM users WHERE verification_token = ? "); $stmt->bind_param("s", $token); $stmt->execute(); $result = $stmt->get_result(); if ($result->num_rows !== 1) { $message = "Invalid or used token."; } else { $user = $result->fetch_assoc(); if ($user['is_verified'] == 1) { $message = "Account already verified."; $type = "info"; } elseif (strtotime($user['verify_expires']) < time()) { $message = "Verification link expired."; } else { $stmt = $conn->prepare(" UPDATE users SET is_verified = 1, verification_token = NULL, verify_expires = NULL WHERE id = ? "); $stmt->bind_param("i", $user['id']); $stmt->execute(); $message = "Your account has been verified! You can now login."; $type = "success"; } } } ?> <!DOCTYPE html> <html> <head> <meta charset="UTF-8"> <title>AskSQL</title> <link rel="icon" type="image/svg+xml" href="../images/database-fill.svg"> <meta name="viewport" content="width=device-width, initial-scale=1.0"> <link rel="stylesheet" href="../css/verify.css"> <link href="https://cdn.jsdelivr.net/npm/bootstrap@5.3.0/dist/css/bootstrap.min.css" rel="stylesheet"> <link href="https://cdn.jsdelivr.net/npm/bootstrap-icons/font/bootstrap-icons.css" rel="stylesheet"> <link rel="stylesheet" href="../css/global.css"> </head> <body class="d-flex align-items-center justify-content-center vh-100"> <div class="card p-4 text-center border-0" style="width: 420px;"> <!-- ICON --> <div class="icon-box mb-3"> <?php if ($type === "success"): ?> <i class="bi bi-check-circle-fill text-success"></i> <?php elseif ($type === "info"): ?> <i class="bi bi-info-circle-fill text-primary"></i> <?php else: ?> <i class="bi bi-x-circle-fill text-danger"></i> <?php endif; ?> </div> <!-- TITLE --> <h5 class="mb-2 fw-semibold">Email Verification</h5> <!-- MESSAGE --> <div class="alert alert-<?php echo $type; ?> mt-3"> <?php echo $message; ?> </div> <!-- BUTTON --> <a href="login.html" class="btn btn-primary w-100 mt-3"> <i class="bi bi-box-arrow-in-right me-2"></i> Go to Login </a> </div> <?php if ($type === "success"): ?> <script> setTimeout(() => { window.location.href = "login.html"; }, 2500); document.querySelectorAll('[data-bs-toggle="tooltip"]').forEach(el => { new bootstrap.Tooltip(el); }); </script> <?php endif; ?> </body> </html>